import{bQ as d,aL as e,u as a,G as s}from"./chunks/framework.D06dwy5q.js";const k=JSON.parse('{"title":"HTTP 和 Web","description":"","frontmatter":{},"headers":[],"relativePath":"00.互联网与架构基础/04-HTTP和Web.md","filePath":"00.互联网与架构基础/04-HTTP和Web.md","lastUpdated":null}'),i={name:"00.互联网与架构基础/04-HTTP和Web.md"};function h(r,t,o,n,p,l){return e(),a("div",null,[...t[0]||(t[0]=[s(`<h1 id="http-和-web" tabindex="-1">HTTP 和 Web <a class="header-anchor" href="#http-和-web" aria-label="Permalink to &quot;HTTP 和 Web&quot;">​</a></h1><p>浏览器找到服务器以后，还要和服务器“说话”。HTTP 就是浏览器和服务端之间最常见的说话格式。浏览器发请求，服务端回响应，网页、图片、接口数据都靠这一来一回传递。</p><p>TCP 负责把连接建起来，TLS 负责给 HTTPS 加密，HTTP 负责说明这次请求要什么、服务端返回了什么。</p><h2 id="一、请求和响应" tabindex="-1">一、请求和响应 <a class="header-anchor" href="#一、请求和响应" aria-label="Permalink to &quot;一、请求和响应&quot;">​</a></h2><p>HTTP 的基本动作很简单：客户端发请求，服务端返回响应。</p><p>一个简化的请求长这样：</p><div class="language-http vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">http</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">GET</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /docs/index.html </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">HTTP</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1.1</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">Host</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> www.example.com</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">User-Agent</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Mozilla/5.0</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">Accept</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> text/html</span></span></code></pre></div><p>服务端可能这样返回：</p><div class="language-http vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">http</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">HTTP</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1.1</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 200</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> OK</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">Content-Type</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> text/html; charset=utf-8</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">Cache-Control</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> max-age=300</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">html</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;...&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">html</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div><p><code>GET</code> 表示读取资源，<code>/docs/index.html</code> 是路径，<code>Host</code> 表示访问哪个域名。<code>200 OK</code> 表示这次请求正常返回。</p><h2 id="二、方法和路径" tabindex="-1">二、方法和路径 <a class="header-anchor" href="#二、方法和路径" aria-label="Permalink to &quot;二、方法和路径&quot;">​</a></h2><p>HTTP 方法表示想做什么，路径表示操作哪个资源。</p><table tabindex="0"><thead><tr><th>方法</th><th>常见含义</th><th>例子</th></tr></thead><tbody><tr><td><code>GET</code></td><td>读取资源</td><td>打开页面、查询列表</td></tr><tr><td><code>POST</code></td><td>创建或提交</td><td>登录、提交表单、创建任务</td></tr><tr><td><code>PUT</code></td><td>整体更新</td><td>更新某个对象</td></tr><tr><td><code>PATCH</code></td><td>局部更新</td><td>修改状态、改一个字段</td></tr><tr><td><code>DELETE</code></td><td>删除资源</td><td>删除任务、删除文件</td></tr></tbody></table><p>浏览器打开页面多数是 <code>GET</code>。前端调用后端接口时，路径常写成 <code>/api/users</code>、<code>/api/tasks/123</code> 这种样子。路径本身只是名字，具体做什么由后端路由和代码决定。</p><h2 id="三、header" tabindex="-1">三、Header <a class="header-anchor" href="#三、header" aria-label="Permalink to &quot;三、Header&quot;">​</a></h2><p>Header 是请求和响应里的附加信息。它不直接显示在页面上，但会影响服务端怎么处理请求、浏览器怎么处理结果。</p><table tabindex="0"><thead><tr><th>Header</th><th>常见作用</th></tr></thead><tbody><tr><td><code>Host</code></td><td>标识访问的域名</td></tr><tr><td><code>Content-Type</code></td><td>请求体或响应体的格式</td></tr><tr><td><code>Authorization</code></td><td>携带登录后的认证信息</td></tr><tr><td><code>Cookie</code></td><td>携带浏览器保存的站点数据</td></tr><tr><td><code>Cache-Control</code></td><td>控制缓存策略</td></tr><tr><td><code>X-Forwarded-For</code></td><td>经过代理后记录原始客户端 IP</td></tr></tbody></table><p>请求经过 Nginx、负载均衡或网关时，Header 可能会被补充或改写。后端看到的客户端 IP 有时会变成上一层代理 IP，这时要看入口层有没有传递 <code>X-Forwarded-For</code> 这类字段。</p><h2 id="四、状态码" tabindex="-1">四、状态码 <a class="header-anchor" href="#四、状态码" aria-label="Permalink to &quot;四、状态码&quot;">​</a></h2><p>状态码是服务端给请求结果贴的标签。它不能直接说明根因，但能给排查方向。</p><table tabindex="0"><thead><tr><th>范围</th><th>含义</th></tr></thead><tbody><tr><td><code>2xx</code></td><td>请求成功</td></tr><tr><td><code>3xx</code></td><td>重定向或缓存</td></tr><tr><td><code>4xx</code></td><td>请求、认证或权限问题</td></tr><tr><td><code>5xx</code></td><td>服务端处理失败</td></tr></tbody></table><p>常见状态码：</p><table tabindex="0"><thead><tr><th>状态码</th><th>用户侧现象</th></tr></thead><tbody><tr><td><code>200</code></td><td>正常返回</td></tr><tr><td><code>301/302</code></td><td>跳到另一个地址</td></tr><tr><td><code>304</code></td><td>浏览器使用缓存</td></tr><tr><td><code>400</code></td><td>请求参数格式不对</td></tr><tr><td><code>401</code></td><td>未登录或认证失败</td></tr><tr><td><code>403</code></td><td>没有权限</td></tr><tr><td><code>404</code></td><td>页面或接口不存在</td></tr><tr><td><code>500</code></td><td>后端处理时报错</td></tr><tr><td><code>502</code></td><td>网关连接后端失败</td></tr><tr><td><code>504</code></td><td>网关等后端等超时</td></tr></tbody></table><p><code>404</code> 可能是前端路径写错，也可能是 Nginx location 没匹配，还可能是后端路由没有注册。<code>502</code> 常见于 Nginx upstream 端口错、后端实例没启动、Kubernetes Service 没有 Endpoints。</p><h2 id="五、登录状态" tabindex="-1">五、登录状态 <a class="header-anchor" href="#五、登录状态" aria-label="Permalink to &quot;五、登录状态&quot;">​</a></h2><p>HTTP 本身不会记住上一次请求是谁。登录状态要靠 Cookie、Session 或 Token 这类机制保存。</p><p>常见过程是：用户登录后，服务端生成一段会话标识，浏览器保存到 Cookie。后续请求自动带上 Cookie，服务端就知道这是哪个用户。</p><p>前后端分离系统也常用 Token。登录接口返回 Token，前端把 Token 放到后续请求的 <code>Authorization</code> Header 里。Cookie 和 Token 都是在 HTTP 请求里携带身份信息，只是保存位置和发送方式不同。</p><h2 id="六、页面和接口" tabindex="-1">六、页面和接口 <a class="header-anchor" href="#六、页面和接口" aria-label="Permalink to &quot;六、页面和接口&quot;">​</a></h2><p>Web 页面通常由两类内容组成：</p><table tabindex="0"><thead><tr><th>类型</th><th>内容</th><th>常见处理方式</th></tr></thead><tbody><tr><td>静态资源</td><td>HTML、CSS、JS、图片、字体</td><td>Nginx、对象存储、CDN</td></tr><tr><td>动态接口</td><td>用户、订单、任务、统计数据</td><td>后端应用、数据库、缓存</td></tr></tbody></table><p>传统网站里，服务端可能直接生成完整 HTML。前后端分离以后，浏览器先拿到静态资源，JavaScript 再调用 API 获取 JSON 数据。</p><div class="mermaid-diagram" data-mermaid-code="flowchart%20LR%0A%20%20Browser%5B%22%E6%B5%8F%E8%A7%88%E5%99%A8%22%5D%0A%20%20Static%5B%22%E9%9D%99%E6%80%81%E8%B5%84%E6%BA%90%3A%20HTML%20%2F%20CSS%20%2F%20JS%22%5D%0A%20%20API%5B%22%E5%90%8E%E7%AB%AF%20API%22%5D%0A%20%20DB%5B%22%E6%95%B0%E6%8D%AE%E5%BA%93%22%5D%0A%0A%20%20Browser%20--%3E%20Static%0A%20%20Browser%20--%3E%20API%0A%20%20API%20--%3E%20DB%0A"></div><p>页面白屏时，可能是 HTML 返回失败，也可能是 JS 文件加载失败，还可能是 JS 加载成功但 API 返回 401、500 或跨域错误。浏览器开发者工具里的 Network 面板能看到每个请求的状态码、耗时和响应内容。</p><p>HTTP 是 Web 系统的共同语言。Nginx、前端、后端、网关、接口文档、监控告警，很多地方最后都会落到请求、响应、状态码和 Header 上。</p>`,35)])])}const E=d(i,[["render",h]]);export{k as __pageData,E as default};
